1	/**
2	 * LayerInfinite MCP Server — gateway-proxy.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
5	 * enrichment) and tools/call (proxy to upstream + auto-mode
6	 * rerouting). Natural language enrichment per mode — never
7	 * bracketed metadata.
8	 *
9	 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
10	 * mode resolution to mode-manager.ts, score fetching to
11	 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { GatewayConfig } from './config.js';
16	import type {
17	  EnrichedTool,
18	  EnrichmentContext,
19	  OutcomePayload,
20	  GatewayMode,
21	} from './types.js';
22	import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
23	import type { UpstreamRegistry } from './upstream-registry.js';
24	import { enqueueOutcome } from './fail-open.js';
25	import { enrichToolList } from './tool-enrichment.js';
26	import { ModeManager } from './mode-manager.js';
27	import { ScoreFetcher } from './enrichment/score-fetcher.js';
28	import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
29	import { logger } from './logger.js';
30	
31	const log = logger.forTool('gateway-proxy');
32	
33	// ── Base62 alphabet ─────────────────────────────────────────
34	
35	const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
36	
37	// ── Auto-mode reroute threshold ─────────────────────────────
38	
39	const REROUTE_CONFIDENCE_THRESHOLD = 0.3;
40	
41	// ══════════════════════════════════════════════════════════════
42	// generateDecisionId
43	// ══════════════════════════════════════════════════════════════
44	
45	function base62Encode(n: number, minLen: number): string {
46	  let s = '';
47	  let v = n;
48	  while (v > 0) {
49	    s = BASE62[v % 62] + s;
50	    v = Math.floor(v / 62);
51	  }
52	  return s.padStart(minLen, '0');
53	}
54	
55	function djb2(s: string): number {
56	  let hash = 5381;
57	  for (let i = 0; i < s.length; i++) {
58	    hash = ((hash << 5) + hash) + s.charCodeAt(i);
59	    hash = hash >>> 0;
60	  }
61	  return hash;
62	}
63	
64	function randomBase62(len: number): string {
65	  let s = '';
66	  for (let i = 0; i < len; i++) {
67	    s += BASE62[Math.floor(Math.random() * 62)];
68	  }
69	  return s;
70	}
71	
72	export function generateDecisionId(agentId: string): string {
73	  const ts12 = base62Encode(Date.now(), 12);
74	  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
75	  const rand4 = randomBase62(4);
76	  return `dec_${ts12}_${agent4}_${rand4}`;
77	}
78	
79	// ══════════════════════════════════════════════════════════════
80	// GatewayProxy
81	// ══════════════════════════════════════════════════════════════
82	
83	export class GatewayProxy {
84	  private readonly modeManager: ModeManager;
85	  private readonly scoreFetcher: ScoreFetcher;
86	
87	  constructor(
88	    private readonly liApi: LiApiClient,
89	    private readonly upstreamClient: UpstreamMCPClient,
90	    private readonly registry: UpstreamRegistry,
91	    private readonly config: GatewayConfig,
92	  ) {
93	    this.modeManager = new ModeManager(config);
94	    this.scoreFetcher = new ScoreFetcher(liApi);
95	  }
96	
97	  // ── tools/list handler ───────────────────────────────────
98	
99	  async handleListTools(taskContext: {
100	    taskType: string;
101	    customerId: string;
102	    agentId: string;
103	  }): Promise<EnrichedTool[]> {
104	    const mode = this.modeManager.resolveMode(taskContext.taskType);
105	
106	    try {
107	      const [rawTools, context] = await Promise.all([
108	        this.upstreamClient.listTools(),
109	        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
110	      ]);
111	
112	      const enriched = enrichToolList(rawTools, context);
113	
114	      // Inject virtual li_recommend tool (only in non-bootstrap modes)
115	      if (mode !== 'bootstrap') {
116	        enriched.push(createLiRecommendTool());
117	      }
118	
119	      // Sort: ranked first, then alphabetically
120	      enriched.sort((a, b) => {
121	        const rankA = a.annotations?.ranking ?? 999;
122	        const rankB = b.annotations?.ranking ?? 999;
123	        if (rankA !== rankB) return rankA - rankB;
124	        return a.name.localeCompare(b.name);
125	      });
126	
127	      log.debug('tools/list enriched', {
128	        count: enriched.length,
129	        mode,
130	        taskType: taskContext.taskType,
131	      });
132	
133	      return enriched;
134	    } catch (err) {
135	      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
136	      // Degrade: return raw tools with no enrichment
137	      try {
138	        const rawTools = await this.upstreamClient.listTools();
139	        return rawTools.map((t) => ({
140	          name: t.name,
141	          description: t.description,
142	          inputSchema: t.inputSchema,
143	          upstreamName: t.upstreamName,
144	        }));
145	      } catch {
146	        return [];
147	      }
148	    }
149	  }
150	
151	  // ── tools/call handler ───────────────────────────────────
152	
153	  async handleCallTool(
154	    toolName: string,
155	    args: Record<string, unknown>,
156	    taskContext: { taskType: string; customerId: string; agentId: string },
157	  ): Promise<UpstreamCallResult> {
158	    const decisionId = generateDecisionId(taskContext.agentId);
159	    const mode = this.modeManager.resolveMode(taskContext.taskType);
160	    const startMs = Date.now();
161	
162	    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
163	    if (toolName === 'li_recommend') {
164	      return handleLiRecommend(
165	        this.liApi,
166	        taskContext.taskType,
167	        taskContext.customerId,
168	        taskContext.agentId,
169	      );
170	    }
171	
172	    // Determine which tool to execute (auto-mode may reroute)
173	    let executedAction = toolName;
174	    let originalAction = toolName;
175	    let rerouted = false;
176	    let enrichmentScores: Record<string, number> = {};
177	
178	    if (mode === 'auto' && !this.config.shadowMode) {
179	      try {
180	        const [scores, policy] = await Promise.all([
181	          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
182	          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
183	        ]);
184	
185	        for (const s of scores) {
186	          enrichmentScores[s.actionName] = s.compositeScore;
187	        }
188	
189	        if (
190	          policy &&
191	          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
192	          policy.action !== toolName &&
193	          this.registry.isHealthy(this.resolveUpstream(policy.action))
194	        ) {
195	          originalAction = toolName;
196	          executedAction = policy.action;
197	          rerouted = true;
198	          log.info('Auto-mode reroute', {
199	            decisionId,
200	            from: toolName,
201	            to: policy.action,
202	            confidence: policy.confidence,
203	            reason: policy.reason,
204	          });
205	        }
206	      } catch {
207	        // Degrade — continue with original tool
208	      }
209	    }
210	
211	    // Resolve upstream from tool name
212	    const upstreamName = this.resolveUpstream(executedAction);
213	
214	    // Proxy to upstream
215	    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);
216	
217	    // Fire-and-forget outcome logging
218	    const latencyMs = Date.now() - startMs;
219	    void this.logDecision({
220	      decisionId,
221	      agentId: taskContext.agentId,
222	      customerId: taskContext.customerId,
223	      taskType: taskContext.taskType,
224	      actionName: executedAction,
225	      upstreamName,
226	      originalAction,
227	      executedAction,
228	      mode,
229	      rerouted,
230	      enrichmentScores,
231	      latencyMs,
232	    });
233	
234	    return result;
235	  }
236	
237	  // ── Shutdown ─────────────────────────────────────────────
238	
239	  async shutdown(): Promise<void> {
240	    this.registry.stopHealthChecks();
241	    log.info('Gateway proxy shut down');
242	  }
243	
244	  // ── Private: enrichment context ──────────────────────────
245	
246	  private async getEnrichmentContext(
247	    taskType: string,
248	    customerId: string,
249	    agentId: string,
250	    mode: GatewayMode,
251	  ): Promise<EnrichmentContext> {
252	    // Bootstrap mode — no enrichment needed
253	    if (mode === 'bootstrap') {
254	      return {
255	        taskType,
256	        customerId,
257	        agentId,
258	        mode,
259	        scores: [],
260	        policyDecision: null,
261	      };
262	    }
263	
264	    try {
265	      const [scores, policyDecision] = await Promise.all([
266	        this.scoreFetcher.getScores(taskType, customerId, agentId),
267	        this.liApi.getPolicyDecision(taskType, customerId, agentId),
268	      ]);
269	
270	      return { taskType, customerId, agentId, mode, scores, policyDecision };
271	    } catch (err) {
272	      log.warn('Enrichment context fetch failed — degrading to bootstrap-like', {
273	        error: err instanceof Error ? err.message : String(err),
274	      });
275	      return {
276	        taskType,
277	        customerId,
278	        agentId,
279	        mode,
280	        scores: [],
281	        policyDecision: null,
282	      };
283	    }
284	  }
285	
286	  // ── Private: routing helpers ─────────────────────────────
287	
288	  private resolveUpstream(toolName: string): string {
289	    const entries = this.registry.getAllUpstreams();
290	    for (const entry of entries) {
291	      if (entry.healthy) return entry.server.name;
292	    }
293	    return entries[0]?.server.name ?? 'unknown';
294	  }
295	
296	  private async logDecision(record: {
297	    decisionId: string;
298	    agentId: string;
299	    customerId: string;
300	    taskType: string;
301	    actionName: string;
302	    upstreamName: string;
303	    originalAction: string;
304	    executedAction: string;
305	    mode: GatewayMode;
306	    rerouted: boolean;
307	    enrichmentScores: Record<string, number>;
308	    latencyMs: number;
309	  }): Promise<void> {
310	    try {
311	      const payload: OutcomePayload = {
312	        decision_id: record.decisionId,
313	        agent_id: record.agentId,
314	        customer_id: record.customerId,
315	        task_type: record.taskType,
316	        action_name: record.actionName,
317	        upstream_name: record.upstreamName,
318	        original_action: record.originalAction,
319	        executed_action: record.executedAction,
320	        mode: record.mode,
321	        rerouted: record.rerouted,
322	        latency_ms: record.latencyMs,
323	        timestamp: new Date().toISOString(),
324	        ingestion_source: 'mcp',
325	        environment: this.config.environment,
326	      };
327	
328	      const sent = await this.liApi.logOutcome(payload);
329	      if (!sent) {
330	        await enqueueOutcome(payload);
331	      }
332	    } catch {
333	      // Fire-and-forget — silent failure is acceptable
334	      log.debug('Outcome logging skipped (non-critical)');
335	    }
336	  }
337	}
