1	/**
2	 * LayerInfinite MCP Server — enrichment/format-recommend.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Recommend-mode description formatting. Informational only —
5	 * provides historical success data with no directional guidance.
6	 * ══════════════════════════════════════════════════════════════
7	 */
8	
9	import type { ScoredAction } from '../types.js';
10	
11	/**
12	 * Format a tool description for Recommend mode.
13	 * Adds historical context as natural language — purely informational.
14	 */
15	export function formatRecommendEnrichment(
16	  description: string,
17	  toolName: string,
18	  taskType: string,
19	  score: ScoredAction | null,
20	  rank: number | null,
21	): string {
22	  const base = description;
23	
24	  // No historical data
25	  if (!score || score.sampleSize < 1) {
26	    return base;
27	  }
28	
29	  const { successRate, sampleSize, trendLabel } = score;
30	  const parts = [base, '', `Historically for "${taskType}" tasks:`];
31	
32	  if (sampleSize < 3) {
33	    parts.push(`${toolName} has been used ${sampleSize} time${sampleSize === 1 ? '' : 's'} (insufficient data for a reliable recommendation).`);
34	  } else if (sampleSize < 10) {
35	    parts.push(`${toolName} has a ${successRate}% success rate (limited data: ${sampleSize} outcomes).`);
36	    if (trendLabel) parts.push(formatTrend(trendLabel));
37	  } else {
38	    parts.push(`${toolName} has a ${successRate}% success rate across ${sampleSize} executions.`);
39	    if (trendLabel) parts.push(formatTrend(trendLabel));
40	  }
41	
42	  if (rank) {
43	    parts.push(`This is the #${rank} recommended tool for this task.`);
44	  }
45	
46	  return parts.filter(Boolean).join('\n');
47	}
48	
49	function formatTrend(trendLabel: string): string {
50	  switch (trendLabel) {
51	    case 'strongly_improving': return 'Success rate is improving significantly.';
52	    case 'improving': return 'Success rate has been improving.';
53	    case 'slightly_improving': return 'Success rate shows a slight positive trend.';
54	    case 'stable': return 'Success rate is stable.';
55	    case 'slightly_declining': return 'Success rate shows a slight decline.';
56	    case 'declining': return 'Success rate has been declining.';
57	    case 'sharply_declining': return 'Success rate is declining significantly.';
58	    default: return '';
59	  }
60	}
61

1	/**
2	 * LayerInfinite MCP Server — enrichment/format-assist.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Assist-mode description formatting. Provides directional
5	 * guidance: recommends the best tool, warns on low performers,
6	 * handles tie-breaking when scores are close.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { ScoredAction } from '../types.js';
11	
12	const CLOSE_RACE_GAP = 5; // percentage points
13	
14	export interface AssistFormatContext {
15	  toolName: string;
16	  taskType: string;
17	  description: string;
18	  score: ScoredAction | null;
19	  rank: number | null;
20	  totalTools: number;
21	  bestScore: ScoredAction | null;
22	}
23	
24	/**
25	 * Format a tool description for Assist mode.
26	 * Includes ranking, comparisons, and warnings for low performers.
27	 */
28	export function formatAssistEnrichment(ctx: AssistFormatContext): string {
29	  const { description, toolName, taskType, score, rank, totalTools, bestScore } = ctx;
30	  const base = description;
31	
32	  // No historical data at all
33	  if (!score || score.sampleSize < 1) {
34	    return `${base}\n\nNo historical data available for this tool on "${taskType}" tasks. Consider testing it in a low-risk context first.`;
35	  }
36	
37	  const lines = [base, '', formatHistoricalContext(toolName, taskType, score)];
38	
39	  // Add ranking guidance
40	  if (rank && score.sampleSize >= 3) {
41	    lines.push(formatRankingGuidance(rank, totalTools, score, bestScore));
42	  }
43	
44	  // Add warning for low performers
45	  lines.push(formatWarning(score, totalTools));
46	
47	  return lines.filter(Boolean).join('\n');
48	}
49	
50	function formatHistoricalContext(
51	  toolName: string,
52	  taskType: string,
53	  score: ScoredAction,
54	): string {
55	  const { successRate, sampleSize, trendLabel } = score;
56	
57	  if (sampleSize < 3) {
58	    return `Historically for "${taskType}" tasks, ${toolName} has been used ${sampleSize} time${sampleSize === 1 ? '' : 's'} (insufficient data for reliability).`;
59	  }
60	
61	  const trendText = trendLabel ? ` ${formatTrendInline(trendLabel)}` : '';
62	  return `Historically for "${taskType}" tasks, ${toolName} has a ${successRate}% success rate across ${sampleSize} executions.${trendText}`;
63	}
64	
65	function formatRankingGuidance(
66	  rank: number,
67	  total: number,
68	  score: ScoredAction,
69	  bestScore: ScoredAction | null,
70	): string {
71	  if (rank === 1) {
72	    // Is this best by a clear margin?
73	    if (bestScore && bestScore.actionName !== score.actionName) {
74	      // Actually find the gap — bestScore is the overall best, but this tool IS rank 1
75	      // Check if there's a close second
76	      return '★ This is the recommended tool for this task.';
77	    }
78	    return '★ This is the recommended tool for this task.';
79	  }
80	
81	  if (bestScore && bestScore.actionName !== score.actionName) {
82	    const gap = bestScore.successRate - score.successRate;
83	    if (gap <= CLOSE_RACE_GAP) {
84	      return `Tied for best option — within ${gap}% of the top-ranked tool (${bestScore.actionName} at ${bestScore.successRate}%).`;
85	    }
86	  }
87	
88	  return `Ranked #${rank} of ${total}. ⚠ Consider the success history when choosing tools.`;
89	}
90	
91	function formatWarning(score: ScoredAction, total: number): string {
92	  const { successRate, sampleSize } = score;
93	
94	  // Only warn when we have enough data
95	  if (sampleSize < 5) return '';
96	
97	  if (successRate < 30) {
98	    return `⚠ WARNING: This tool has a critically low success rate (${successRate}%). Strongly consider alternatives.`;
99	  }
100	
101	  if (successRate < 50) {
102	    const altCount = total > 1 ? ` ${total - 1} alternative${total > 2 ? 's' : ''} available` : '';
103	    return `⚠ CAUTION: This tool fails more than half the time (${successRate}% success).${altCount ? `Consider using one of the${altCount}.` : ''}`;
104	  }
105	
106	  return '';
107	}
108	
109	function formatTrendInline(trendLabel: string): string {
110	  switch (trendLabel) {
111	    case 'strongly_improving': return 'and has been improving significantly';
112	    case 'improving': return 'and has been improving';
113	    case 'slightly_improving': return 'with a slight positive trend';
114	    case 'stable': return ''; // no trend text for stable
115	    case 'slightly_declining': return 'with a slight negative trend';
116	    case 'declining': return 'but has been declining';
117	    case 'sharply_declining': return 'but has been declining significantly';
118	    default: return '';
119	  }
120	}
