1	/**
2	 * LayerInfinite API — routes/business-webhook.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * POST /v1/webhook/callback — Business outcome webhook endpoint.
5	 *
6	 * Receives Layer 2 (session) and Layer 3 (business) outcome signals
7	 * linked via decision_id. Validates HMAC signature, resolves the
8	 * original outcome, and orchestrates the 3-layer score overwrite.
9	 *
10	 * Idempotent: duplicate (decision_id + layer) → 200 (replayed).
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Context } from 'hono';
15	import { z } from 'zod';
16	import {
17	  verifyBusinessWebhook,
18	  isTimestampValid,
19	  checkRateLimit,
20	} from '../lib/webhook-verifier.js';
21	import { handleWebhookCallback } from '../lib/outcome-orchestrator.js';
22	
23	// ── Request schema ───────────────────────────────────────────
24	
25	const WebhookCallbackBody = z.object({
26	  decision_id: z.string().min(1).max(255),
27	  layer: z
28	    .number()
29	    .int()
30	    .refine((v) => v === 2 || v === 3, { message: 'layer must be 2 (session) or 3 (business)' }),
31	  success: z.boolean(),
32	  score: z
33	    .number()
34	    .min(0)
35	    .max(1)
36	    .default(0.5),
37	  reason: z.string().max(500).optional(),
38	  metadata: z.record(z.string(), z.unknown()).optional(),
39	  timestamp: z.string().datetime().optional(),
40	});
41	
42	// ── POST /v1/webhook/callback ────────────────────────────────
43	
44	export default async function businessWebhookRoute(c: Context): Promise<Response> {
45	  // ── 1. Rate limit ─────────────────────────────────────────
46	  const customerId = c.get('customer_id') as string | undefined;
47	  if (customerId && !checkRateLimit(customerId)) {
48	    return c.json(
49	      { error: 'Rate limit exceeded', code: 'RATE_LIMITED', retry_after_ms: 60_000 },
50	      429,
51	    );
52	  }
53	
54	  // ── 2. Parse body ─────────────────────────────────────────
55	  let body: z.infer<typeof WebhookCallbackBody>;
56	  try {
57	    body = WebhookCallbackBody.parse(await c.req.json());
58	  } catch (err: any) {
59	    const details = err.errors
60	      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
61	      : err.message;
62	    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
63	  }
64	
65	  // ── 3. Verify webhook signature ───────────────────────────
66	  // In production, always enforce HMAC verification.
67	  // In development, allow unverified requests for testing.
68	  if (process.env.NODE_ENV === 'production') {
69	    const rawBody = JSON.stringify(body);
70	    const signatureHeader = c.req.header('X-LI-Webhook-Signature');
71	
72	    if (!customerId) {
73	      return c.json({ error: 'Missing customer context', code: 'MISSING_CUSTOMER_ID' }, 401);
74	    }
75	
76	    const verified = await verifyBusinessWebhook(rawBody, signatureHeader, customerId);
77	    if (!verified) {
78	      return c.json({ error: 'Invalid webhook signature', code: 'UNAUTHORIZED' }, 401);
79	    }
80	  }
81	
82	  // ── 4. Validate timestamp (if provided in header) ─────────
83	  const headerTimestamp = c.req.header('X-LI-Webhook-Timestamp');
84	  if (headerTimestamp) {
85	    const ts = Number(headerTimestamp);
86	    if (Number.isFinite(ts) && !isTimestampValid(ts)) {
87	      return c.json(
88	        { error: 'Webhook timestamp expired (>24h old or in the future)', code: 'TIMESTAMP_EXPIRED' },
89	        400,
90	      );
91	    }
92	  }
93	
94	  // ── 5. Process callback via orchestrator ──────────────────
95	  try {
96	    const result = await handleWebhookCallback({
97	      decisionId: body.decision_id,
98	      layer: body.layer as 2 | 3,
99	      success: body.success,
100	      score: body.score,
101	      reason: body.reason,
102	      metadata: body.metadata,
103	      timestamp: body.timestamp ?? new Date().toISOString(),
104	    });
105	
106	    if (!result.resolved) {
107	      return c.json(
108	        {
109	          resolved: false,
110	          decision_id: body.decision_id,
111	          message: 'No outcome found for the given decision_id. The outcome may not have been logged yet.',
112	          code: 'DECISION_NOT_FOUND',
113	        },
114	        200,
115	      );
116	    }
117	
118	    const statusCode = result.idempotent ? 200 : 202;
119	
120	    return c.json(
121	      {
122	        resolved: true,
123	        outcome_id: result.outcomeId,
124	        decision_id: body.decision_id,
125	        layer: result.layer,
126	        previous_score: result.previousScore,
127	        new_score: result.newScore,
128	        idempotent_replay: result.idempotent,
129	        message: result.idempotent
130	          ? 'Webhook callback already processed (idempotent replay).'
131	          : 'Webhook callback accepted. Score overwrite applied.',
132	      },
133	      statusCode,
134	    );
135	  } catch (err: any) {
136	    console.error('[business-webhook] callback processing failed:', err.message);
137	    return c.json(
138	      { error: 'Failed to process webhook callback', details: err.message, code: 'PROCESSING_ERROR' },
139	      500,
140	    );
141	  }
142	}
