1	/**
2	 * LayerInfinite API — lib/model-versioning.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Model version tracking for world_model_artifacts.
5	 *
6	 * Operations:
7	 *   - List version history for a customer
8	 *   - Rollback: deactivate current version, re-activate a previous one
9	 *   - Pin: lock a task_type to a specific model version
10	 *   - Unpin: remove a pin
11	 *   - Diff: compare two versions (training_episodes delta, trained_at)
12	 *
13	 * Cache invalidation: after rollback/pin, invalidates the world-model
14	 * module-level cache so next predictOutcome() picks up the change.
15	 * ══════════════════════════════════════════════════════════════
16	 */
17	
18	import { supabase } from './supabase.js';
19	import { invalidateModelCache } from './simulation/world-model.js';
20	
21	// ── Types ──────────────────────────────────────────────────────
22	
23	export interface ModelVersionSummary {
24	  version: number;
25	  trained_at: string;
26	  training_episodes: number;
27	  is_active: boolean;
28	  is_canary: boolean;
29	  canary_traffic_pct: number;
30	  tier: number;
31	  customer_id: string;
32	}
33	
34	export interface VersionDiff {
35	  from_version: number;
36	  to_version: number;
37	  episode_delta: number;
38	  time_delta_hours: number;
39	  from_trained_at: string;
40	  to_trained_at: string;
41	}
42	
43	export interface ModelPin {
44	  task_type: string;
45	  pinned_version: number;
46	  pinned_at: string;
47	  pinned_by?: string;
48	}
49	
50	// ── Public API ─────────────────────────────────────────────────
51	
52	/**
53	 * List all model versions for a customer, newest first.
54	 */
55	export async function listModelVersions(
56	  customerId: string,
57	  limit = 20,
58	): Promise<ModelVersionSummary[]> {
59	  const { data, error } = await supabase
60	    .from('world_model_artifacts')
61	    .select('version, trained_at, training_episodes, is_active, is_canary, canary_traffic_pct, tier, customer_id')
62	    .eq('customer_id', customerId)
63	    .order('version', { ascending: false })
64	    .limit(limit);
65	
66	  if (error || !data) {
67	    console.warn('[model-versioning] Failed to list versions:', error?.message);
68	    return [];
69	  }
70	
71	  return data as ModelVersionSummary[];
72	}
73	
74	/**
75	 * Get the currently active version for a customer.
76	 */
77	export async function getActiveVersion(
78	  customerId: string,
79	): Promise<ModelVersionSummary | null> {
80	  const { data, error } = await supabase
81	    .from('world_model_artifacts')
82	    .select('version, trained_at, training_episodes, is_active, is_canary, canary_traffic_pct, tier, customer_id')
83	    .eq('customer_id', customerId)
84	    .eq('is_active', true)
85	    .order('version', { ascending: false })
86	    .limit(1)
87	    .maybeSingle();
88	
89	  if (error || !data) return null;
90	  return data as ModelVersionSummary;
91	}
92	
93	/**
94	 * Rollback to a previous model version.
95	 *
96	 * Deactivates the current active model and re-activates the target version.
97	 * Invalidates the world-model cache so subsequent predictions use the rolled-back model.
98	 */
99	export async function rollbackModel(
100	  customerId: string,
101	  targetVersion: number,
102	): Promise<{ success: boolean; previousVersion: number | null; newVersion: number; error?: string }> {
103	  const active = await getActiveVersion(customerId);
104	
105	  if (!active) {
106	    return { success: false, previousVersion: null, newVersion: targetVersion, error: 'No active model found' };
107	  }
108	
109	  if (active.version === targetVersion) {
110	    return { success: false, previousVersion: active.version, newVersion: targetVersion, error: 'Target version is already active' };
111	  }
112	
113	  // Verify target version exists
114	  const { data: target, error: targetError } = await supabase
115	    .from('world_model_artifacts')
116	    .select('version, customer_id')
117	    .eq('customer_id', customerId)
118	    .eq('version', targetVersion)
119	    .maybeSingle();
120	
121	  if (targetError || !target) {
122	    return { success: false, previousVersion: active.version, newVersion: targetVersion, error: `Version ${targetVersion} not found` };
123	  }
124	
125	  // Deactivate current
126	  const { error: deactivateError } = await supabase
127	    .from('world_model_artifacts')
128	    .update({ is_active: false })
129	    .eq('customer_id', customerId)
130	    .eq('version', active.version);
131	
132	  if (deactivateError) {
133	    return { success: false, previousVersion: active.version, newVersion: targetVersion, error: deactivateError.message };
134	  }
135	
136	  // Activate target
137	  const { error: activateError } = await supabase
138	    .from('world_model_artifacts')
139	    .update({ is_active: true })
140	    .eq('customer_id', customerId)
141	    .eq('version', targetVersion);
142	
143	  if (activateError) {
144	    // Rollback the deactivation
145	    await supabase
146	      .from('world_model_artifacts')
147	      .update({ is_active: true })
148	      .eq('customer_id', customerId)
149	      .eq('version', active.version);
150	    return { success: false, previousVersion: active.version, newVersion: targetVersion, error: activateError.message };
151	  }
152	
153	  invalidateModelCache(customerId);
154	
155	  console.info(
156	    `[model-versioning] Rollback: customer=${customerId} ` +
157	    `v${active.version} → v${targetVersion}`,
158	  );
159	
160	  return { success: true, previousVersion: active.version, newVersion: targetVersion };
161	}
162	
163	/**
164	 * Compute a diff between two model versions.
165	 */
166	export async function diffVersions(
167	  customerId: string,
168	  fromVersion: number,
169	  toVersion: number,
170	): Promise<VersionDiff | null> {
171	  const { data, error } = await supabase
172	    .from('world_model_artifacts')
173	    .select('version, trained_at, training_episodes')
174	    .eq('customer_id', customerId)
175	    .in('version', [fromVersion, toVersion])
176	    .order('version', { ascending: true });
177	
178	  if (error || !data || data.length < 2) return null;
179	
180	  const from = data[0] as { version: number; trained_at: string; training_episodes: number };
181	  const to = data[1] as { version: number; trained_at: string; training_episodes: number };
182	
183	  const timeDeltaMs = new Date(to.trained_at).getTime() - new Date(from.trained_at).getTime();
184	
185	  return {
186	    from_version: from.version,
187	    to_version: to.version,
188	    episode_delta: to.training_episodes - from.training_episodes,
189	    time_delta_hours: Math.round((timeDeltaMs / 3_600_000) * 100) / 100,
190	    from_trained_at: from.trained_at,
191	    to_trained_at: to.trained_at,
192	  };
193	}
194	
195	// ── Pin Management ─────────────────────────────────────────────
196	
197	/**
198	 * Pin a task_type to a specific model version.
199	 * Pins are stored in dim_agents.config.pinned_models as a JSONB object:
200	 *   { "task_type": version_number, ... }
201	 *
202	 * Pins are global (per customer), not per-agent.
203	 * Uses a dedicated model_pins table if it exists, otherwise falls back
204	 * to an in-memory store (pins survive process lifetime only).
205	 */
206	const pinStore = new Map<string, Map<string, ModelPin>>();
207	
208	function pinKey(customerId: string): string {
209	  return `customer:${customerId}`;
210	}
211	
212	export async function pinModelVersion(
213	  customerId: string,
214	  taskType: string,
215	  version: number,
216	  pinnedBy?: string,
217	): Promise<ModelPin> {
218	  const pin: ModelPin = {
219	    task_type: taskType,
220	    pinned_version: version,
221	    pinned_at: new Date().toISOString(),
222	    pinned_by: pinnedBy,
223	  };
224	
225	  const key = pinKey(customerId);
226	  let customerPins = pinStore.get(key);
227	  if (!customerPins) {
228	    customerPins = new Map();
229	    pinStore.set(key, customerPins);
230	  }
231	  customerPins.set(taskType, pin);
232	
233	  // Persist to model_pins table
234	  try {
235	    await supabase.from('model_pins').upsert({
236	      customer_id: customerId,
237	      task_type: taskType,
238	      pinned_version: version,
239	      pinned_at: pin.pinned_at,
240	      pinned_by: pinnedBy ?? null,
241	    }, { onConflict: 'customer_id,task_type' });
242	  } catch (err: any) {
243	    console.warn('[model-versioning] Pin persist failed:', err.message);
244	  }
245	
246	  console.info(
247	    `[model-versioning] Pin: customer=${customerId} ` +
248	    `task_type=${taskType} → v${version}`,
249	  );
250	
251	  return pin;
252	}
253	
254	export async function unpinModelVersion(
255	  customerId: string,
256	  taskType: string,
257	): Promise<boolean> {
258	  const key = pinKey(customerId);
259	  const customerPins = pinStore.get(key);
260	  const existed = customerPins?.delete(taskType) ?? false;
261	
262	  try {
263	    await supabase
264	      .from('model_pins')
265	      .delete()
266	      .eq('customer_id', customerId)
267	      .eq('task_type', taskType);
268	  } catch (err: any) {
269	    console.warn('[model-versioning] Pin delete failed:', err.message);
270	  }
271	
272	  if (existed) {
273	    console.info(`[model-versioning] Unpin: customer=${customerId} task_type=${taskType}`);
274	  }
275	
276	  return existed;
277	}
278	
279	export async function getPinnedVersion(
280	  customerId: string,
281	  taskType: string,
282	): Promise<number | null> {
283	  const key = pinKey(customerId);
284	  const customerPins = pinStore.get(key);
285	  const memoryPin = customerPins?.get(taskType);
286	  if (memoryPin) return memoryPin.pinned_version;
287	
288	  // Try DB
289	  try {
290	    const { data, error } = await supabase
291	      .from('model_pins')
292	      .select('pinned_version')
293	      .eq('customer_id', customerId)
294	      .eq('task_type', taskType)
295	      .maybeSingle();
296	
297	    if (error || !data) return null;
298	
299	    const version = (data as { pinned_version: number }).pinned_version;
300	    // Populate memory cache
301	    const customerPins = pinStore.get(key) ?? new Map();
302	    customerPins.set(taskType, {
303	      task_type: taskType,
304	      pinned_version: version,
305	      pinned_at: new Date().toISOString(),
306	    });
307	    pinStore.set(key, customerPins);
308	
309	    return version;
310	  } catch {
311	    return null;
312	  }
313	}
314	
315	export async function listPins(customerId: string): Promise<ModelPin[]> {
316	  const key = pinKey(customerId);
317	  const customerPins = pinStore.get(key);
318	  const memoryPins = customerPins ? Array.from(customerPins.values()) : [];
319	
320	  // Merge with DB
321	  try {
322	    const { data, error } = await supabase
323	      .from('model_pins')
324	      .select('task_type, pinned_version, pinned_at, pinned_by')
325	      .eq('customer_id', customerId);
326	
327	    if (error || !data) return memoryPins;
328	
329	    const dbPins = data as ModelPin[];
330	    const merged = new Map<string, ModelPin>();
331	    for (const p of memoryPins) merged.set(p.task_type, p);
332	    for (const p of dbPins) {
333	      if (!merged.has(p.task_type)) merged.set(p.task_type, p);
334	    }
335	    return Array.from(merged.values());
336	  } catch {
337	    return memoryPins;
338	  }
339	}
