1	/**
2	 * LayerInfinite API — routes/model-history.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Admin routes for model version history, rollback, and pinning.
5	 *
6	 * GET    /v1/admin/model-history          — list versions
7	 * GET    /v1/admin/model-history/:v1/:v2  — diff two versions
8	 * POST   /v1/admin/model-history/rollback — rollback to a version
9	 * POST   /v1/admin/model-history/pin      — pin task_type to version
10	 * DELETE /v1/admin/model-history/pin      — remove a pin
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Hono } from 'hono';
15	import { z } from 'zod';
16	import {
17	  listModelVersions,
18	  getActiveVersion,
19	  rollbackModel,
20	  diffVersions,
21	  pinModelVersion,
22	  unpinModelVersion,
23	  listPins,
24	} from '../lib/model-versioning.js';
25	
26	export const modelHistoryRouter = new Hono();
27	
28	// ── GET / — list versions ─────────────────────────────────────
29	
30	modelHistoryRouter.get('/', async (c) => {
31	  const customerId = c.req.query('customer_id');
32	  if (!customerId) {
33	    return c.json({ error: 'customer_id query parameter is required', code: 'MISSING_CUSTOMER_ID' }, 400);
34	  }
35	
36	  const limit = Math.min(100, Math.max(1, Number(c.req.query('limit')) || 20));
37	
38	  try {
39	    const versions = await listModelVersions(customerId, limit);
40	    const active = await getActiveVersion(customerId);
41	    const pins = await listPins(customerId);
42	
43	    return c.json({
44	      customer_id: customerId,
45	      active_version: active?.version ?? null,
46	      version_count: versions.length,
47	      pins: pins.map((p) => ({
48	        task_type: p.task_type,
49	        pinned_version: p.pinned_version,
50	        pinned_at: p.pinned_at,
51	      })),
52	      versions: versions.map((v) => ({
53	        version: v.version,
54	        trained_at: v.trained_at,
55	        training_episodes: v.training_episodes,
56	        is_active: v.is_active,
57	        is_canary: v.is_canary,
58	        canary_traffic_pct: v.canary_traffic_pct,
59	        tier: v.tier,
60	      })),
61	    }, 200);
62	  } catch (err: any) {
63	    return c.json({ error: 'Failed to list versions', details: err.message, code: 'LIST_ERROR' }, 500);
64	  }
65	});
66	
67	// ── GET /:fromVersion/:toVersion — diff ────────────────────────
68	
69	modelHistoryRouter.get('/:fromVersion/:toVersion', async (c) => {
70	  const customerId = c.req.query('customer_id');
71	  if (!customerId) {
72	    return c.json({ error: 'customer_id query parameter is required', code: 'MISSING_CUSTOMER_ID' }, 400);
73	  }
74	
75	  const fromVersion = Number(c.req.param('fromVersion'));
76	  const toVersion = Number(c.req.param('toVersion'));
77	
78	  if (!Number.isFinite(fromVersion) || !Number.isFinite(toVersion)) {
79	    return c.json({ error: 'Version parameters must be integers', code: 'VALIDATION_ERROR' }, 400);
80	  }
81	
82	  try {
83	    const diff = await diffVersions(customerId, fromVersion, toVersion);
84	    if (!diff) {
85	      return c.json({ error: 'Could not compute diff — one or both versions not found', code: 'NOT_FOUND' }, 404);
86	    }
87	
88	    return c.json(diff, 200);
89	  } catch (err: any) {
90	    return c.json({ error: 'Failed to compute diff', details: err.message, code: 'DIFF_ERROR' }, 500);
91	  }
92	});
93	
94	// ── POST /rollback — rollback to a version ─────────────────────
95	
96	const RollbackBody = z.object({
97	  customer_id: z.string().min(1),
98	  target_version: z.number().int().positive(),
99	});
100	
101	modelHistoryRouter.post('/rollback', async (c) => {
102	  let body: z.infer<typeof RollbackBody>;
103	  try {
104	    body = RollbackBody.parse(await c.req.json());
105	  } catch (err: any) {
106	    const details = err.errors
107	      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
108	      : err.message;
109	    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
110	  }
111	
112	  try {
113	    const result = await rollbackModel(body.customer_id, body.target_version);
114	
115	    if (!result.success) {
116	      return c.json({
117	        success: false,
118	        previous_version: result.previousVersion,
119	        attempted_version: body.target_version,
120	        error: result.error,
121	        code: 'ROLLBACK_FAILED',
122	      }, 400);
123	    }
124	
125	    return c.json({
126	      success: true,
127	      previous_version: result.previousVersion,
128	      new_version: result.newVersion,
129	      message: `Rolled back from v${result.previousVersion} to v${result.newVersion}`,
130	    }, 200);
131	  } catch (err: any) {
132	    return c.json({ error: 'Rollback failed', details: err.message, code: 'ROLLBACK_ERROR' }, 500);
133	  }
134	});
135	
136	// ── POST /pin — pin task_type to version ───────────────────────
137	
138	const PinBody = z.object({
139	  customer_id: z.string().min(1),
140	  task_type: z.string().min(1).max(255),
141	  version: z.number().int().positive(),
142	  pinned_by: z.string().optional(),
143	});
144	
145	modelHistoryRouter.post('/pin', async (c) => {
146	  let body: z.infer<typeof PinBody>;
147	  try {
148	    body = PinBody.parse(await c.req.json());
149	  } catch (err: any) {
150	    const details = err.errors
151	      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
152	      : err.message;
153	    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
154	  }
155	
156	  try {
157	    const pin = await pinModelVersion(body.customer_id, body.task_type, body.version, body.pinned_by);
158	
159	    return c.json({
160	      pinned: true,
161	      task_type: pin.task_type,
162	      pinned_version: pin.pinned_version,
163	      pinned_at: pin.pinned_at,
164	      message: `Pinned "${body.task_type}" to v${body.version}`,
165	    }, 200);
166	  } catch (err: any) {
167	    return c.json({ error: 'Pin failed', details: err.message, code: 'PIN_ERROR' }, 500);
168	  }
169	});
170	
171	// ── DELETE /pin — remove pin ───────────────────────────────────
172	
173	const UnpinBody = z.object({
174	  customer_id: z.string().min(1),
175	  task_type: z.string().min(1).max(255),
176	});
177	
178	modelHistoryRouter.delete('/pin', async (c) => {
179	  let body: z.infer<typeof UnpinBody>;
180	  try {
181	    body = UnpinBody.parse(await c.req.json());
182	  } catch (err: any) {
183	    const details = err.errors
184	      ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
185	      : err.message;
186	    return c.json({ error: 'Invalid request body', details, code: 'VALIDATION_ERROR' }, 400);
187	  }
188	
189	  try {
190	    const unpinned = await unpinModelVersion(body.customer_id, body.task_type);
191	
192	    return c.json({
193	      unpinned,
194	      task_type: body.task_type,
195	      message: unpinned
196	        ? `Unpinned "${body.task_type}"`
197	        : `No pin found for "${body.task_type}"`,
198	    }, 200);
199	  } catch (err: any) {
200	    return c.json({ error: 'Unpin failed', details: err.message, code: 'UNPIN_ERROR' }, 500);
201	  }
202	});
