2	
3	/**
4	 * LayerInfinite MCP Server — bin/cli.ts
5	 * ══════════════════════════════════════════════════════════════
6	 * Entry point for stdio transport. This is what Claude Desktop,
7	 * Cursor, Cline, and other MCP hosts spawn as a child process.
8	 *
9	 * Usage:
10	 *   LAYERINFINITE_API_KEY=xxx npx layerinfinite-mcp
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
15	import { createGatewayServer } from '../src/index.js';
16	import { logger } from '../src/logger.js';
17	
18	const log = logger.forTool('cli');
19	
20	let shuttingDown = false;
21	
22	async function main() {
23	  log.info('LayerInfinite Gateway starting', { version: '2.0.0' });
24	
25	  const gateway = createGatewayServer();
26	  const { server, proxy, upstreamClient, registry } = gateway;
27	
28	  // Start upstream health checks
29	  upstreamClient.startHealthChecks();
30	
31	  const transport = new StdioServerTransport();
32	
33	  async function shutdown(signal: string) {
34	    if (shuttingDown) return;
35	    shuttingDown = true;
36	    log.info('Shutting down', { signal });
37	
38	    try {
39	      registry.stopHealthChecks();
40	      await proxy.shutdown();
41	      await server.close();
42	      log.info('Server closed cleanly');
43	    } catch (err) {
44	      log.error('Error during shutdown', {
45	        error: err instanceof Error ? err.message : String(err),
46	      });
47	    }
48	
49	    process.exit(0);
50	  }
51	
52	  process.on('SIGINT', () => shutdown('SIGINT'));
53	  process.on('SIGTERM', () => shutdown('SIGTERM'));
54	  process.on('unhandledRejection', (reason) => {
55	    log.error('Unhandled rejection', {
56	      error: reason instanceof Error ? reason.message : String(reason),
57	      stack: reason instanceof Error ? reason.stack : undefined,
58	    });
59	  });
60	
61	  await server.connect(transport);
62	  log.info('Gateway connected via stdio', {
63	    mode: gateway.config.mode ?? 'bootstrap',
64	    upstreams: gateway.config.upstreamServers.length,
65	  });
66	}
67	
68	main().catch((err) => {
69	  log.error('Fatal startup error', {
70	    error: err instanceof Error ? err.message : String(err),
71	    stack: err instanceof Error ? err.stack : undefined,
72	  });
73	  process.exit(1);
74	});
